 1	import React, { FC } from 'react';
 2	import { useForm } from 'react-hook-form';
 3	import { useNavigate } from 'react-router-dom-v5-compat';
 4	
 5	import { DataSourceModelRef } from '@kubevirt-ui/kubevirt-api/console/models/DataSourceModel';
 6	import { DEFAULT_DISK_SIZE } from '@kubevirt-utils/components/DiskModal/utils/constants';
 7	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 8	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 9	import { DEFAULT_NAMESPACE } from '@kubevirt-utils/constants/constants';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import { generatePrettyName } from '@kubevirt-utils/utils/utils';
12	import { Stack, StackItem } from '@patternfly/react-core';
13	
14	import { CreateDataSourceForm } from './CreateDataSourceForm';
15	import { createDataSourceWithImportCron } from './utils';
16	
17	export type CreateDataSourceModalFormType = {
18	  importsToKeep: number;
19	  name: string;
20	  schedule: string;
21	  size: string;
22	  url: string;
23	};
24	
25	type CreateDataSourceModalProps = {
26	  isOpen: boolean;
27	  namespace: string;
28	  onClose: () => void;
29	};
30	
31	export const CreateDataSourceModal: FC<CreateDataSourceModalProps> = ({
32	  isOpen,
33	  namespace,
34	  onClose,
35	}) => {
36	  const { t } = useKubevirtTranslation();
37	  const navigate = useNavigate();
38	
39	  const {
40	    formState: { errors },
41	    handleSubmit,
42	    register,
43	    setValue,
44	    watch,
45	  } = useForm<CreateDataSourceModalFormType>({
46	    defaultValues: {
47	      importsToKeep: 3,
48	      name: generatePrettyName('datasource'),
49	      size: DEFAULT_DISK_SIZE,
50	    },
51	  });
52	  const importsToKeep = watch('importsToKeep');
53	  const size = watch('size');
54	  const name = watch('name');
55	
56	  const onSubmit = handleSubmit(
57	    (data) =>
58	      createDataSourceWithImportCron({
59	        ...data,
60	        namespace: namespace || DEFAULT_NAMESPACE,
61	        url: data?.url?.includes('docker://') ? data?.url : 'docker://' + data?.url,
62	      }).then(() =>
63	        navigate(`/k8s/ns/${namespace || DEFAULT_NAMESPACE}/${DataSourceModelRef}/${name}`),
64	      ),
65	    () => Promise.reject({ message: t('Missing required fields') }),
66	  );
67	
68	  return (
69	    <TabModal
70	      headerText={t('Create DataSource')}
71	      isOpen={isOpen}
72	      onClose={onClose}
73	      onSubmit={() => onSubmit()}
74	    >
75	      <Stack hasGutter>
76	        <StackItem>
77	          <MutedTextSpan
78	            text={t(
79	              'Creates a DataImportCron, which defines a cron job to poll and import the disk image.',
80	            )}
81	          />
82	        </StackItem>
83	        <StackItem>
84	          <CreateDataSourceForm
85	            errors={errors}
86	            importsToKeep={importsToKeep}
87	            register={register}
88	            setValue={setValue}
89	            size={size}
90	          />
91	        </StackItem>
92	      </Stack>
93	    </TabModal>
94	  );
95	};

